// `estimate` (story 211) is the async meal-estimate-ready notification — a
// third server-initiated category after the health (missed-meal) and learning
// (SRS due-card) reminders, mutable independently in settings.
export const NOTIFICATION_CATEGORIES = ['learning', 'health', 'social', 'coaching', 'estimate'] as const;
export type NotificationCategory = (typeof NOTIFICATION_CATEGORIES)[number];

export type NotificationPreferences = Record<NotificationCategory, boolean>;

export const DEFAULT_NOTIFICATION_PREFERENCES: NotificationPreferences = {
    learning: true,
    health: true,
    social: true,
    coaching: true,
    estimate: true,
};

export interface PushSubscriptionPayload {
    endpoint: string;
    keys: {
        p256dh: string;
        auth: string;
    };
}

export interface NotificationPayload {
    title: string;
    body: string;
    tag: string;
    data: {
        path: string;
        category?: NotificationCategory;
    };
}
